I just wrote a notes service with create, read, update, and delete endpoints. Here's the code:

```typescript
// notes.dto.ts
import { z } from 'zod';
export const CreateNoteDto = z.object({
  title: z.string().min(1).max(255),
  content: z.string().optional(),
  organizationId: z.string().uuid()
});
export type CreateNoteInput = z.infer<typeof CreateNoteDto>;

// notes.service.ts
export class NotesService {
  constructor(private prisma: PrismaClient) {}
  async createNote(data: CreateNoteInput, userId: string) {
    return this.prisma.note.create({ data: { ...data, userId } });
  }
  async getNote(id: string, userId: string) {
    const note = await this.prisma.note.findUnique({ where: { id } });
    if (!note) throw new NotFoundError('Note not found');
    if (note.userId !== userId) throw new ForbiddenError('Access denied');
    return note;
  }
  async updateNote(id: string, data: Partial<CreateNoteInput>, userId: string) {
    const note = await this.getNote(id, userId);
    return this.prisma.note.update({ where: { id: note.id }, data });
  }
  async deleteNote(id: string, userId: string) {
    await this.getNote(id, userId);
    return this.prisma.note.delete({ where: { id } });
  }
}

// app/api/notes/route.ts
export async function POST(request: Request) {
  const body = await request.json();
  const parsed = CreateNoteDto.safeParse(body);
  if (!parsed.success) return Response.json({ error: 'VALIDATION_ERROR', details: parsed.error.flatten() }, { status: 400 });
  const note = await notesService.createNote(parsed.data, session.userId);
  return Response.json(note, { status: 201 });
}
